type exitError struct {
	code int
	err  error
}

func (e *exitError) Error() string {
	if e == nil || e.err == nil {
		return fmt.Sprintf("cli: exit %d", e.code)
	}
	return e.err.Error()
}

func (e *exitError) Unwrap() error {
