func mustCasesByName(t *testing.T, names ...string) []Case {
	t.Helper()

	all, err := LoadCorpus()
	if err != nil {
		t.Fatalf("LoadCorpus: %v", err)
	}
	index := make(map[string]Case, len(all))
	for _, tc := range all {
		index[tc.Name] = tc
	}
	out := make([]Case, 0, len(names))
	for _, name := range names {
		tc, ok := index[name]
		if !ok {
			t.Fatalf("missing corpus case %q", name)
		}
		out = append(out, tc)
	}
	return out

